from flask import Flask, request, jsonify
import json

app = Flask(__name__)

def load_todos():
    try:
        with open('todos.json', 'r') as f:
            return json.load(f)
    except FileNotFoundError:
        return []

def save_todos(todos):
    with open('todos.json', 'w') as f:
        json.dump(todos, f, indent=4)

@app.route('/')
def home():
    return "Todo List API"

# GET all todos
@app.route('/todos', methods=['GET'])
def get_todos():
    todos = load_todos()
    return jsonify(todos)

# GET a single todo by ID
@app.route('/todos/<int:todo_id>', methods=['GET'])
def get_todo(todo_id):
    todos = load_todos()
    todo = next((todo for todo in todos if todo['id'] == todo_id), None)
    if todo:
        return jsonify(todo)
    return jsonify({'message': 'Todo not found'}), 404

# POST a new todo
@app.route('/todos', methods=['POST'])
def add_todo():
    if not request.json or not 'title' in request.json:
        return jsonify({'message': 'Invalid input: missing title'}), 400

    todos = load_todos()
    new_id = max([todo['id'] for todo in todos]) + 1 if todos else 1

    new_todo = {
        'id': new_id,
        'title': request.json['title'],
        'description': request.json.get('description', ''),
        'done': False
    }

    # Validate 'done' field if provided
    if 'done' in request.json and not isinstance(request.json['done'], bool):
        return jsonify({'message': 'Invalid input: "done" field must be a boolean'}), 400
    if 'done' in request.json:
        new_todo['done'] = request.json['done']

    todos.append(new_todo)
    save_todos(todos)
    return jsonify(new_todo), 201

# PUT (update) a todo by ID
@app.route('/todos/<int:todo_id>', methods=['PUT'])
def update_todo(todo_id):
    todos = load_todos()
    todo = next((todo for todo in todos if todo['id'] == todo_id), None)
    if not todo:
        return jsonify({'message': 'Todo not found'}), 404

    if not request.json:
        return jsonify({'message': 'Invalid input'}), 400

    # Validate and update fields
    if 'title' in request.json and not isinstance(request.json['title'], str):
        return jsonify({'message': 'Invalid input: "title" field must be a string'}), 400
    if 'description' in request.json and not isinstance(request.json['description'], str):
        return jsonify({'message': 'Invalid input: "description" field must be a string'}), 400
    if 'done' in request.json and not isinstance(request.json['done'], bool):
        return jsonify({'message': 'Invalid input: "done" field must be a boolean'}), 400

    todo['title'] = request.json.get('title', todo['title'])
    todo['description'] = request.json.get('description', todo['description'])
    todo['done'] = request.json.get('done', todo['done'])

    save_todos(todos)
    return jsonify(todo)

# DELETE a todo by ID
@app.route('/todos/<int:todo_id>', methods=['DELETE'])
def delete_todo(todo_id):
    todos = load_todos()
    todo_to_delete = next((todo for todo in todos if todo['id'] == todo_id), None)
    if not todo_to_delete:
        return jsonify({'message': 'Todo not found'}), 404

    todos.remove(todo_to_delete)
    save_todos(todos)
    return jsonify({'message': 'Todo deleted'})

if __name__ == '__main__':
    app.run(debug=True)

